 17â†’internal class BasicFormatStructure<in T>(
 18â†’    val directive: FieldFormatDirective<T>
 19â†’) : NonConcatenatedFormatStructure<T> {
 20â†’    override fun toString(): String = "BasicFormatStructure($directive)"
 21â†’
 22â†’    override fun equals(other: Any?): Boolean = other is BasicFormatStructure<*> && directive == other.directive
 23â†’    override fun hashCode(): Int = directive.hashCode()
 24â†’
 25â†’    override fun parser(): ParserStructure<T> = directive.parser()
