255â†’private fun <T> basicFormats(format: FormatStructure<T>): List<FieldFormatDirective<T>> = buildList {
256â†’    fun rec(format: FormatStructure<T>) {
257â†’        when (format) {
258â†’            is BasicFormatStructure -> add(format.directive)
259â†’            is ConcatenatedFormatStructure -> format.formats.forEach { rec(it) }
260â†’            is ConstantFormatStructure -> {}
261â†’            is SignedFormatStructure -> rec(format.format)
262â†’            is AlternativesParsingFormatStructure -> {
263â†’                rec(format.mainFormat); format.formats.forEach { rec(it) }
264â†’            }
265â†’
266â†’            is OptionalFormatStructure -> rec(format.format)
267â†’        }
268â†’    }
269â†’    rec(format)
270â†’}
